angular.module('starter').controller('IAP_HomeController',function($scope){});angular.module('starter').factory('IAP_Product',function($pwaRequest){var factory={};factory.all=function(){return $pwaRequest.get('inapppurchase/mobile_product/all')};return factory});angular.module('starter').factory('IAP_Purchase',function($pwaRequest){var factory={};factory.all=function(){return $pwaRequest.get('inapppurchase/mobile_purchase/all')};return factory});angular.module('starter').service('IAP_Store',function(SB){var service={};service.init=function(){};service.registerCollection=function(collection){if(store===undefined){console.error('[IAP Store] store is not available.');return}
store.ready(function(){collection.forEach(function(product){store.register({id:DEVICE_TYPE===SB.DEVICE.TYPE_ANDROID?product.google_id:product.apple_id,alias:product.alias,type:store[product.type]})})})};return service});angular.module('starter').service('IAP_Init',function(IAP_Product,IAP_Store,SB){var service={};service.onStart=function(){if(SB.DEVICE.TYPE_BROWSER===DEVICE_TYPE){console.info('IAP[Support]: InAppPurchase are not available on the WebApp/Browser.');return}
IAP_Store.init();IAP_Product.all().then(function(payload){IAP_Store.registerCollection(payload.collection)},function(error){console.log('IAP[Error]: ',error)})};return service});Features.insertCSS("","purchase")